const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

/**
 * Register a new user with their voice recording
 * @param {string} username
 * @param {Blob} audioBlob
 * @returns {Promise<{success: boolean, message: string}>}
 */
export async function registerVoice(username, audioBlob) {
  const formData = new FormData();
  formData.append("username", username);
  formData.append(
    "audio",
    new File([audioBlob], "recording.webm", { type: "audio/webm" })
  );

  const res = await fetch(`${API_URL}/register`, {
    method: "POST",
    body: formData,
  });

  const text = await res.text();
  const success =
    text.toLowerCase().includes("successful") ||
    text.toLowerCase().includes("success");

  return { success, message: success ? "Registration successful!" : "Registration failed.", raw: text };
}

/**
 * Authenticate a user with their voice recording
 * @param {string} username
 * @param {Blob} audioBlob
 * @returns {Promise<object>} parsed result data
 */
export async function authenticateVoice(username, audioBlob) {
  const formData = new FormData();
  formData.append("username", username);
  formData.append(
    "audio",
    new File([audioBlob], "recording.webm", { type: "audio/webm" })
  );

  const res = await fetch(`${API_URL}/authenticate`, {
    method: "POST",
    body: formData,
  });

  if (!res.ok) {
    throw new Error(`Server error: ${res.status}`);
  }

  const html = await res.text();
  return parseResultHTML(html, API_URL);
}

/**
 * Parse the Flask result HTML into structured data
 */
function parseResultHTML(html, apiUrl) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(html, "text/html");

  const result = {
    status: "Unknown",
    access: "Denied",
    similarity: 0,
    real_prob: 0,
    fake_prob: 0,
    distance: null,
    reason: "",
    reg_spec: null,
    login_spec: null,
    grad_img: null,
    report: null,
  };

  // Extract status from h1
  const h1 = doc.querySelector("h1");
  if (h1) result.status = h1.textContent.trim();

  // Extract paragraphs
  doc.querySelectorAll("p").forEach((p) => {
    const text = p.textContent.trim();
    if (text.startsWith("Speaker Similarity:"))
      result.similarity = parseFloat(text.split(":")[1]) || 0;
    if (text.startsWith("Real Probability:"))
      result.real_prob = parseFloat(text.split(":")[1]) || 0;
    if (text.startsWith("Fake Probability:"))
      result.fake_prob = parseFloat(text.split(":")[1]) || 0;
    if (text.startsWith("Access:"))
      result.access = text.replace("Access:", "").trim();
    if (text.startsWith("Reason:"))
      result.reason = text.replace("Reason:", "").trim();
  });

  // Extract images — rewrite relative URLs to absolute
  doc.querySelectorAll("img").forEach((img) => {
    const src = img.getAttribute("src") || "";
    const fullSrc = src.startsWith("http") ? src : `${apiUrl}/static/${src.replace(/^\/static\//, "")}`;
    if (src.includes("_reg.png")) result.reg_spec = fullSrc;
    if (src.includes("_login.png")) result.login_spec = fullSrc;
    if (src.includes("gradcam")) result.grad_img = fullSrc;
  });

  // Extract report link
  doc.querySelectorAll("a").forEach((a) => {
    const href = a.getAttribute("href") || "";
    if (href.includes("report") || a.textContent.includes("Report")) {
      result.report = href.startsWith("http") ? href : `${apiUrl}/static/${href.replace(/^\/static\//, "")}`;
    }
  });

  return result;
}
